    return null;
}

const QuickActions: React.FC<{ onActionSuccess: (description: string) => void }> = ({ onActionSuccess }) => {
    const [isFabOpen, setIsFabOpen] = useState(false);
    const [activeModal, setActiveModal] = useState<ModalType | null>(null);
    const [modalStep, setModalStep] = useState(1);

    const [accounts, setAccounts] = useState<Account[]>([]);
    const [categories, setCategories] = useState<Category[]>([]);
    const [contacts, setContacts] = useState<Contact[]>([]);
    const [unpaidDebts, setUnpaidDebts] = useState<Debt[]>([]);

    const fetchDataForModals = useCallback(async () => {
        const accPromise = supabase.from('accounts').select('*');
        const catPromise = supabase.from('categories').select('*');
        const conPromise = supabase.from('contacts').select('*');
        const debtPromise = supabase.from('debts').select('*, contacts(name)').eq('paid', false);

        const [{ data: accData }, { data: catData }, { data: conData }, { data: debtData }] = await Promise.all([accPromise, catPromise, conPromise, debtPromise]);

        setAccounts(accData as Account[] || []);
        setCategories(catData as Category[] || []);
        setContacts(conData as Contact[] || []);
        setUnpaidDebts(debtData as unknown as Debt[] || []);
    }, []);

    useEffect(() => {
        if(activeModal) fetchDataForModals();
    }, [activeModal, fetchDataForModals]);

    const handleActionSuccess = () => {
        let description = 'تم تحديث البيانات'; // Default
        switch (activeModal) {
            case 'expense': description = 'إضافة مصروف جديد'; break;
            case 'income': description = 'إضافة إيراد جديد'; break;
            case 'transfer': description = 'إجراء تحويل مالي'; break;
            case 'add-debt': description = 'إضافة دين جديد'; break;
            case 'settle-debt': description = 'تسوية دين'; break;
            case 'add-account': description = 'إضافة حساب جديد'; break;
        }
        setActiveModal(null);
        setModalStep(1);
        setIsFabOpen(false);
        onActionSuccess(description);
    };

    const openModal = (type: ModalType) => {
        setActiveModal(type);
        setIsFabOpen(false);
    }

    const closeModal = () => {
        setActiveModal(null);
        setModalStep(1);
    }

    const fabActions = [
        // Core Transactions
        { label: 'إضافة مصروف', icon: <ArrowUpIcon className="w-6 h-6"/>, action: () => openModal('expense'), gradient: 'from-rose-500 to-pink-600' },
        { label: 'إضافة إيراد', icon: <ArrowDownIcon className="w-6 h-6"/>, action: () => openModal('income'), gradient: 'from-emerald-500 to-teal-600' },
        { label: 'تحويل', icon: <ArrowsRightLeftIcon className="w-6 h-6"/>, action: () => openModal('transfer'), gradient: 'from-violet-500 to-indigo-600' },
        // Debt Management
        { label: 'إضافة دين', icon: <HandRaisedIcon className="w-6 h-6"/>, action: () => openModal('add-debt'), gradient: 'from-amber-500 to-orange-600' },
        { label: 'تسوية دين', icon: <ScaleIcon className="w-6 h-6"/>, action: () => openModal('settle-debt'), gradient: 'from-sky-500 to-blue-600' },
        // Entity Creation
        { label: 'إضافة حساب', icon: <AccountsIcon className="w-6 h-6"/>, action: () => openModal('add-account'), gradient: 'from-slate-600 to-slate-700' },
    ];

    const modalTitles: Record<ModalType, string> = {
        expense: 'مصروف جديد',
        income: 'إيراد جديد',
        transfer: 'تحويل أموال',
        'add-debt': 'تسجيل دين',
        'settle-debt': 'تسوية الديون',
        'add-account': 'حساب جديد'
    };

    const renderModalContent = () => {
        switch(activeModal) {
            case 'expense':
            case 'income':
                return <TransactionModal type={activeModal} accounts={accounts} categories={categories} onSuccess={handleActionSuccess} onCancel={closeModal} />;
            case 'transfer':
                 return <TransferModal accounts={accounts} onSuccess={handleActionSuccess} onCancel={closeModal} />;
            case 'add-debt':
                return <AddDebtWizard contacts={contacts} accounts={accounts} categories={categories} onSuccess={handleActionSuccess} onCancel={closeModal} step={modalStep} setStep={setModalStep} />;
            case 'settle-debt':
                return <SettleDebtWizard unpaidDebts={unpaidDebts} contacts={contacts} accounts={accounts} categories={categories} onSuccess={handleActionSuccess} step={modalStep} setStep={setModalStep} />
            case 'add-account':
                return <AddAccountModal onSuccess={handleActionSuccess} onCancel={closeModal} />;
            default:
                return null;
        }
    }


    return (
        <>
            {/* Scrim Overlay */}
            <div
                className={`fixed inset-0 bg-slate-950/80 backdrop-blur-sm z-40 transition-opacity duration-300 ease-in-out ${isFabOpen ? 'opacity-100' : 'opacity-0 pointer-events-none'}`}
                onClick={() => setIsFabOpen(false)}
                aria-hidden="true"
            />

            {/* FAB and Actions Container */}
            <div className="fixed bottom-28 md:bottom-10 left-6 z-50 flex flex-col items-center gap-4 pointer-events-none">
                {/* Actions List */}
                <div className={`flex flex-col-reverse items-center gap-3 transition-all duration-300 mb-2 ${isFabOpen ? 'translate-y-0 opacity-100 pointer-events-auto' : 'translate-y-4 opacity-0 pointer-events-none'}`}>
                    {fabActions.map((action, index) => (
                        <div
                            key={index}
                            className="flex items-center gap-3"
                            style={{ transitionDelay: `${isFabOpen ? index * 30 : 0}ms` }}
                        >
                             <span className="bg-slate-900/90 text-slate-200 text-xs font-bold py-1.5 px-3 rounded-lg shadow-xl backdrop-blur-md border border-slate-700 whitespace-nowrap animate-fade-in">
                                {action.label}
                            </span>
                             <button onClick={action.action} className={`h-11 w-11 rounded-full text-white flex items-center justify-center shadow-lg shadow-black/50 hover:brightness-110 transition-all hover:scale-110 active:scale-95 border border-white/10 bg-gradient-to-br ${action.gradient}`}>
                                {action.icon}
                            </button>
                        </div>
                    ))}
                </div>

                {/* FAB Button */}
                <button
                    onClick={() => setIsFabOpen(!isFabOpen)}
                    className={`pointer-events-auto group relative h-14 w-14 md:h-16 md:w-16 bg-slate-900 rounded-full shadow-[0_0_20px_rgba(8,145,178,0.4)] flex items-center justify-center transition-all duration-300 z-50 border border-cyan-500/30 overflow-visible hover:scale-105 active:scale-95 ${isFabOpen ? 'rotate-45 bg-slate-800 border-rose-500/50 text-rose-500 shadow-rose-500/20' : 'text-cyan-400'}`}
                    aria-haspopup="true"
                    aria-expanded={isFabOpen}
                    aria-label={isFabOpen ? 'إغلاق الإجراءات السريعة' : 'فتح الإجراءات السريعة'}
                >
                    {!isFabOpen && <span className="absolute inset-0 rounded-full border border-cyan-400/30 animate-ping-slow"></span>}
                    <PlusIcon className="w-8 h-8 transition-transform duration-300" />
                </button>
            </div>

            {activeModal && (
                <Modal 
                  title={modalTitles[activeModal]}
                  onClose={closeModal}
                  showBackButton={modalStep > 1}
                  onBack={() => setModalStep(s => s - 1)}
                 >
                    {renderModalContent()}
                </Modal>
            )}
        </>
    );
};

export default QuickActions;

import React, { createContext, useContext, useState, useCallback, useEffect } from 'react';
import { CheckCircleIcon, XMarkIcon, ExclamationTriangleIcon, InformationCircleIcon } from './icons';

type ToastType = 'success' | 'error' | 'warning' | 'info';

interface Toast {
    id: string;
    message: string;
    type: ToastType;
}

interface ToastContextType {
    addToast: (message: string, type: ToastType) => void;
    success: (message: string) => void;
    error: (message: string) => void;
    warning: (message: string) => void;
    info: (message: string) => void;
}

const ToastContext = createContext<ToastContextType | undefined>(undefined);

export const useToast = () => {
    const context = useContext(ToastContext);
    if (!context) {
        throw new Error('useToast must be used within a ToastProvider');
    }
    return context;
};

const ToastItem: React.FC<{ toast: Toast; onRemove: (id: string) => void }> = ({ toast, onRemove }) => {
    const [isExiting, setIsExiting] = useState(false);

    useEffect(() => {
        const timer = setTimeout(() => {
            handleClose();
        }, 4000); // Auto dismiss after 4 seconds
        return () => clearTimeout(timer);
    }, []);

    const handleClose = () => {
        setIsExiting(true);
        setTimeout(() => {
            onRemove(toast.id);
        }, 300); // Wait for exit animation
    };

    const styles = {
        success: { icon: CheckCircleIcon, color: 'text-emerald-400', border: 'border-emerald-500/30', bg: 'bg-emerald-950/40' },
        error: { icon: XMarkIcon, color: 'text-rose-400', border: 'border-rose-500/30', bg: 'bg-rose-950/40' },
        warning: { icon: ExclamationTriangleIcon, color: 'text-amber-400', border: 'border-amber-500/30', bg: 'bg-amber-950/40' },
        info: { icon: InformationCircleIcon, color: 'text-cyan-400', border: 'border-cyan-500/30', bg: 'bg-cyan-950/40' },
    }[toast.type];

    const Icon = styles.icon;

    return (
        <div 
            className={`pointer-events-auto w-full max-w-sm overflow-hidden rounded-2xl border ${styles.border} ${styles.bg} backdrop-blur-xl shadow-2xl flex items-center gap-4 p-4 transition-all duration-300 transform ${isExiting ? 'opacity-0 translate-y-[-20px] scale-95' : 'opacity-100 translate-y-0 scale-100'} animate-slide-up`}
            role="alert"
        >
            <div className={`shrink-0 ${styles.color}`}>
                <Icon className="w-6 h-6" />
            </div>
            <div className="flex-1">
                <p className="font-bold text-white text-sm leading-snug">{toast.message}</p>
            </div>
            <button onClick={handleClose} className="shrink-0 p-1.5 rounded-full hover:bg-white/10 text-slate-400 hover:text-white transition-colors">
                <XMarkIcon className="w-4 h-4" />
            </button>
        </div>
    );
};

export const ToastProvider: React.FC<{ children: React.ReactNode }> = ({ children }) => {
    const [toasts, setToasts] = useState<Toast[]>([]);

    const addToast = useCallback((message: string, type: ToastType) => {
        const id = Math.random().toString(36).substring(2, 9);
        setToasts((prev) => [...prev, { id, message, type }]);
    }, []);

    const removeToast = useCallback((id: string) => {
        setToasts((prev) => prev.filter((t) => t.id !== id));
    }, []);

    // Helper functions
    const success = (msg: string) => addToast(msg, 'success');
    const error = (msg: string) => addToast(msg, 'error');
    const warning = (msg: string) => addToast(msg, 'warning');
    const info = (msg: string) => addToast(msg, 'info');

    return (
        <ToastContext.Provider value={{ addToast, success, error, warning, info }}>
            {children}

            {/* Toast Container */}
            <div className="fixed top-4 left-0 right-0 z-[100] flex flex-col items-center gap-3 px-4 pointer-events-none">
                {toasts.map((toast) => (
                    <ToastItem key={toast.id} toast={toast} onRemove={removeToast} />
                ))}
            </div>
        </ToastContext.Provider>
    );
};

import React, { useState, useCallback, useEffect } from 'react';
import { Page } from './types';
import Header from './components/Header';
import Sidebar from './components/Sidebar';
import HomePage from './components/HomePage';
import AccountsPage from './components/AccountsPage';
import TransactionsPage from './components/TransactionsPage';
import DebtsPage from './components/DebtsPage';
import ContactsPage from './components/ContactsPage';
import ContactProfilePage from './components/ContactProfilePage';
import CategoriesPage from './components/CategoriesPage';
import ReportsPage from './components/ReportsPage';
import NotesPage from './components/NotesPage';
import BottomNav from './components/BottomNav';
import { ToastProvider } from './components/Toast';
import { supabase } from './lib/supabase';
import { WalletIcon } from './components/icons';

function App() {
  const [isAuthenticated, setIsAuthenticated] = useState(false);
  const [passwordInput, setPasswordInput] = useState('');
  const [authError, setAuthError] = useState('');

  const [activePage, setActivePage] = useState<Page>('home');
  const [isSidebarOpen, setSidebarOpen] = useState(false);
  const [key, setKey] = useState(0);
  const [debtNotificationCount, setDebtNotificationCount] = useState(0);
  const [activeContactId, setActiveContactId] = useState<string | null>(null);
  const [activeContactName, setActiveContactName] = useState<string>('');

  useEffect(() => {
    if (localStorage.getItem('app_authenticated') === 'true') {
      setIsAuthenticated(true);
    }
  }, []);

  const handlePasswordSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (passwordInput === '9991') {
      localStorage.setItem('app_authenticated', 'true');
      setIsAuthenticated(true);
      setAuthError('');
    } else {
      setAuthError('كلمة المرور غير صحيحة');
      setPasswordInput('');
    }
  };


  const handleDatabaseChange = useCallback(async (description?: string) => {
    if (description) {
      const now = new Date();
      const activity_date = now.toISOString().split('T')[0];
      const activity_time = now.toTimeString().split(' ')[0];

      const { error } = await supabase.from('activities').upsert({
        id: 1,
        activity_date,
        activity_time,
        description,
      });

      if (error) {
        console.error("Error logging activity:", error.message);
      }
    }
    setKey(prevKey => prevKey + 1);
  }, []);


  useEffect(() => {
    if (!isAuthenticated) return;

    const fetchAppData = async () => {
      const { data: debtData, error: debtError } = await supabase
        .from('debts')
        .select('due_date')
        .eq('paid', false)
        .not('due_date', 'is', null);

      if (debtError || !debtData) {
        console.error("Error fetching debts for notifications", debtError?.message);
        setDebtNotificationCount(0);
      } else {
        const today = new Date();
        today.setHours(0, 0, 0, 0);

        const sevenDaysFromNow = new Date();
        sevenDaysFromNow.setHours(23, 59, 59, 999);
        sevenDaysFromNow.setDate(today.getDate() + 7);

        const count = debtData.filter(debt => {
          const dueDate = new Date(debt.due_date!);
          if (dueDate < today) return true;
          if (dueDate >= today && dueDate <= sevenDaysFromNow) return true;
          return false;
        }).length;
        setDebtNotificationCount(count);
      }
    };

    fetchAppData();
  }, [key, isAuthenticated]);

  const handleSelectContact = async (contactId: string) => {
    setActiveContactId(contactId);
    try {
        const { data, error } = await supabase.from('contacts').select('name').eq('id', contactId).single();
        if (error) throw error;
        setActiveContactName(data?.name || 'ملف شخصي');
        setActivePage('contacts');
    } catch(e) {
        console.error("Error fetching contact name", e);
        setActiveContactName('ملف شخصي');
        setActivePage('contacts');
    }
  };

  const handleBackToContacts = () => {
    setActiveContactId(null);
    setActiveContactName('');
    setActivePage('contacts');
    handleDatabaseChange();
  };

  const renderPage = () => {
    if (activePage === 'contacts' && activeContactId) {
        return <ContactProfilePage 
            key={activeContactId} 
            contactId={activeContactId} 
            onBack={handleBackToContacts} 
            handleDatabaseChange={handleDatabaseChange} 
        />;
    }

    switch (activePage) {
      case 'home': return <HomePage key={key} handleDatabaseChange={handleDatabaseChange} setActivePage={setActivePage} />;
      case 'accounts': return <AccountsPage key={key} handleDatabaseChange={handleDatabaseChange} />;
      case 'transactions': return <TransactionsPage key={key} handleDatabaseChange={handleDatabaseChange} />;
      case 'debts': return <DebtsPage key={key} handleDatabaseChange={handleDatabaseChange} onSelectContact={handleSelectContact} />;
      case 'contacts': return <ContactsPage key={key} handleDatabaseChange={handleDatabaseChange} onSelectContact={handleSelectContact} />;
      case 'categories': return <CategoriesPage key={key} handleDatabaseChange={handleDatabaseChange} />;
      case 'reports': return <ReportsPage key={key} />;
      case 'notes': return <NotesPage key={key} handleDatabaseChange={handleDatabaseChange} />;
      default: return <HomePage key={key} handleDatabaseChange={handleDatabaseChange} setActivePage={setActivePage}/>;
    }
  };

  if (!isAuthenticated) {
    return (
      <div className="min-h-screen font-sans flex items-center justify-center p-4 relative overflow-hidden" dir="rtl">
         {/* Ambient background elements */}
        <div className="absolute top-0 left-1/4 w-96 h-96 bg-cyan-500/20 rounded-full blur-[100px] animate-pulse-slow"></div>
        <div className="absolute bottom-0 right-1/4 w-96 h-96 bg-blue-600/20 rounded-full blur-[100px] animate-pulse-slow" style={{animationDelay: '2s'}}></div>

        <div className="glass-card w-full max-w-sm p-8 rounded-3xl shadow-2xl text-center animate-slide-up relative z-10">
          <div className="w-20 h-20 bg-gradient-to-br from-cyan-400 to-blue-600 rounded-2xl mx-auto mb-8 flex items-center justify-center shadow-lg shadow-cyan-500/30 rotate-3 hover:rotate-0 transition-transform duration-500">
             <WalletIcon className="w-10 h-10 text-white" />
          </div>
          <h1 className="text-3xl font-bold text-white mb-2 tracking-tight">أهلاً بعودتك</h1>
          <p className="text-slate-400 mb-8 text-sm font-medium">أدخل رمز المرور للمتابعة</p>
          <form onSubmit={handlePasswordSubmit} className="space-y-6">
            <div className="relative group">
                <input
                type="password"
                value={passwordInput}
                onChange={(e) => setPasswordInput(e.target.value)}
                className="w-full bg-slate-950/50 border border-slate-700/50 rounded-2xl p-4 text-white text-center text-2xl tracking-[0.5em] focus:outline-none focus:ring-2 focus:ring-cyan-500/50 focus:border-cyan-500 transition-all placeholder-slate-700 group-hover:border-slate-600"
                placeholder="••••"
                autoFocus
                />
            </div>
            {authError && <p className="text-rose-400 text-sm font-medium animate-bounce bg-rose-500/10 py-2 rounded-lg border border-rose-500/20">{authError}</p>}
            <button
              type="submit"
              className="w-full bg-gradient-to-r from-cyan-500 to-blue-600 hover:from-cyan-400 hover:to-blue-500 text-white font-bold py-4 rounded-2xl transition-all transform active:scale-95 shadow-lg shadow-cyan-500/20"
            >
              دخول
            </button>
          </form>
        </div>
      </div>
    );
  }

  return (
    <ToastProvider>
        <div className="min-h-screen font-sans pb-24 md:pb-0" dir="rtl">
        <Header 
            activePage={activePage} 
            onMenuClick={() => setSidebarOpen(true)}
            isProfilePage={!!activeContactId}
            profileName={activeContactName}
            onBack={handleBackToContacts}
        />
        <Sidebar isOpen={isSidebarOpen} onClose={() => setSidebarOpen(false)} activePage={activePage} setActivePage={setActivePage} />
        <main className="max-w-5xl mx-auto p-4 md:p-6 animate-fade-in">
            {renderPage()}
        </main>
        <BottomNav activePage={activePage} setActivePage={setActivePage} debtNotificationCount={debtNotificationCount} />
        </div>
    </ToastProvider>
  );
}

export default App;

