import React, { useState } from 'react';
import { supabase } from '../lib/supabase';
import { Transaction, Account, Category } from '../types';
import { useToast } from './Toast';

interface TransactionFormProps {
    transaction?: Transaction;
    onSave: () => void;
    onCancel: () => void;
    accounts: Account[];
    categories: Category[];
}

const TransactionForm: React.FC<TransactionFormProps> = ({ transaction, onSave, onCancel, accounts, categories }) => {
    const toast = useToast();
    const [type, setType] = useState<'income' | 'expense'>(transaction?.type === 'income' ? 'income' : 'expense');
    const [amount, setAmount] = useState(transaction?.amount?.toString() || '');
    const [notes, setNotes] = useState(transaction?.notes || '');
    const [accountId, setAccountId] = useState(transaction?.account_id || '');
    const [categoryId, setCategoryId] = useState(transaction?.category_id || '');
    const [date, setDate] = useState(transaction?.date ? new Date(transaction.date).toISOString().split('T')[0] : new Date().toISOString().split('T')[0]);
    const [isSaving, setIsSaving] = useState(false);

    const handleSubmit = async (e: React.FormEvent) => {
        e.preventDefault();
        if (!accountId) {
            toast.warning("الرجاء اختيار حساب.");
            return;
        }
        setIsSaving(true);

        const isUpdate = !!transaction?.id;
        const newAmountValue = Number(amount);

        try {
            const finalDate = new Date(`${date}T00:00:00`); // Local midnight on selected day
            const originalDateString = transaction?.date ? new Date(transaction.date).toISOString().split('T')[0] : null;

            // If it's an update and the date part hasn't changed, preserve the original time.
            if (isUpdate && transaction?.date && date === originalDateString) {
                const originalDate = new Date(transaction.date);
                finalDate.setHours(originalDate.getHours());
                finalDate.setMinutes(originalDate.getMinutes());
                finalDate.setSeconds(originalDate.getSeconds());
            } else {
                // For new transactions or if the date was changed on an existing one, use the current time.
                const now = new Date();
                finalDate.setHours(now.getHours());
                finalDate.setMinutes(now.getMinutes());
                finalDate.setSeconds(now.getSeconds());
            }

            // Using an RPC is safer for handling balance updates atomically.
            // This prevents race conditions and ensures data integrity.
            const { error } = await supabase.rpc('save_transaction_and_update_balance', {
                p_is_update: isUpdate,
                p_transaction_id: isUpdate ? transaction.id : null,
                p_account_id: accountId,
                p_type: type,
                p_amount: newAmountValue,
                p_date: finalDate.toISOString(),
                p_category_id: categoryId || null,
                p_notes: notes,
                p_old_account_id: isUpdate ? transaction.account_id : null,
                p_old_type: isUpdate ? transaction.type : null,
                p_old_amount: isUpdate ? transaction.amount : null,
            });

            if (error) throw error;
            onSave();
        } catch (error: any) {
            console.error('Error saving transaction:', error.message);
            toast.error('حدث خطأ أثناء حفظ المعاملة. تأكد من أن دالة قاعدة البيانات RPC موجودة.');
        } finally {
            setIsSaving(false);
        }
    };

    const filteredCategories = categories.filter(c => c.type === type);

    return (
        <form onSubmit={handleSubmit} className="space-y-4">
            <div>
                <label className="block text-sm font-medium text-slate-300 mb-1">نوع المعاملة</label>
                <div className="flex gap-4">
                    <button type="button" onClick={() => { setType('expense'); setCategoryId(''); }} className={`w-full p-2 rounded-md ${type === 'expense' ? 'bg-red-500 text-white' : 'bg-slate-700'}`}>مصروف</button>
                    <button type="button" onClick={() => { setType('income'); setCategoryId(''); }} className={`w-full p-2 rounded-md ${type === 'income' ? 'bg-green-500 text-white' : 'bg-slate-700'}`}>دخل</button>
                </div>
            </div>
            <div>
                <label htmlFor="amount" className="block text-sm font-medium text-slate-300 mb-1">المبلغ</label>
                <input type="number" step="0.01" id="amount" value={amount} onChange={e => setAmount(e.target.value)} required className="w-full bg-slate-700 border border-slate-600 rounded-md p-2 text-white focus:ring-cyan-500 focus:border-cyan-500" />
            </div>
             <div>
                <label htmlFor="account" className="block text-sm font-medium text-slate-300 mb-1">الحساب</label>
                <select id="account" value={accountId} onChange={e => setAccountId(e.target.value)} required className="w-full bg-slate-700 border border-slate-600 rounded-md p-2 text-white focus:ring-cyan-500 focus:border-cyan-500">
                    <option value="" disabled>اختر حساب</option>
                    {accounts.map(acc => <option key={acc.id} value={acc.id}>{acc.name}</option>)}
                </select>
            </div>
             <div>
                <label htmlFor="category" className="block text-sm font-medium text-slate-300 mb-1">الفئة</label>
                <select id="category" value={categoryId || ''} onChange={e => setCategoryId(e.target.value)} className="w-full bg-slate-700 border border-slate-600 rounded-md p-2 text-white focus:ring-cyan-500 focus:border-cyan-500">
                    <option value="">بدون فئة</option>
                    {filteredCategories.map(cat => <option key={cat.id} value={cat.id}>{cat.name}</option>)}
                </select>
            </div>
             <div>
                <label htmlFor="date" className="block text-sm font-medium text-slate-300 mb-1">التاريخ</label>
                <input type="date" id="date" value={date} onChange={e => setDate(e.target.value)} required className="w-full bg-slate-700 border border-slate-600 rounded-md p-2 text-white focus:ring-cyan-500 focus:border-cyan-500" />
            </div>
             <div>
                <label htmlFor="notes" className="block text-sm font-medium text-slate-300 mb-1">ملاحظات</label>
                <input type="text" id="notes" value={notes} onChange={e => setNotes(e.target.value)} className="w-full bg-slate-700 border border-slate-600 rounded-md p-2 text-white focus:ring-cyan-500 focus:border-cyan-500" />
            </div>
            <div className="flex justify-end gap-3 pt-4">
                <button type="button" onClick={onCancel} className="py-2 px-4 bg-slate-600 hover:bg-slate-500 rounded-md transition">إلغاء</button>
                <button type="submit" disabled={isSaving} className="py-2 px-4 bg-cyan-600 hover:bg-cyan-500 rounded-md transition disabled:bg-slate-500 disabled:cursor-not-allowed">
                    {isSaving ? 'جاري الحفظ...' : 'حفظ'}
                </button>
            </div>
        </form>
    );
}

export default TransactionForm;

import React, { useState, useEffect } from 'react';
import { Page } from './types';
import Header from './components/Header';
import Sidebar from './components/Sidebar';
import HomePage from './components/HomePage';
import AccountsPage from './components/AccountsPage';
import TransactionsPage from './components/TransactionsPage';
import DebtsPage from './components/DebtsPage';
import ContactsPage from './components/ContactsPage';
import ContactProfilePage from './components/ContactProfilePage';
import CategoriesPage from './components/CategoriesPage';
import ReportsPage from './components/ReportsPage';
import NotesPage from './components/NotesPage';
import BottomNav from './components/BottomNav';
import { ToastProvider } from './components/Toast';
import { supabase } from './lib/supabase';
import { WalletIcon } from './components/icons';
import { QueryClient, QueryClientProvider, useQuery } from '@tanstack/react-query';

// Create a client
const queryClient = new QueryClient({
  defaultOptions: {
    queries: {
      staleTime: 1000 * 60 * 5, // 5 minutes
      gcTime: 1000 * 60 * 60, // 1 hour (formerly cacheTime)
      refetchOnWindowFocus: false,
    },
  },
});

function AppContent() {
  const [isAuthenticated, setIsAuthenticated] = useState(false);
  const [passwordInput, setPasswordInput] = useState('');
  const [authError, setAuthError] = useState('');

  const [activePage, setActivePage] = useState<Page>('home');
  const [isSidebarOpen, setSidebarOpen] = useState(false);

  // Removed explicit key state for forcing re-renders; React Query handles invalidation now.
  const [activeContactId, setActiveContactId] = useState<string | null>(null);
  const [activeContactName, setActiveContactName] = useState<string>('');

  useEffect(() => {
    if (localStorage.getItem('app_authenticated') === 'true') {
      setIsAuthenticated(true);
    }
  }, []);

  const handlePasswordSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (passwordInput === '9991') {
      localStorage.setItem('app_authenticated', 'true');
      setIsAuthenticated(true);
      setAuthError('');
    } else {
      setAuthError('كلمة المرور غير صحيحة');
      setPasswordInput('');
    }
  };

  // Use React Query for Debt Notifications
  const { data: debtNotificationCount = 0 } = useQuery({
    queryKey: ['debtNotifications'],
    queryFn: async () => {
        const { data: debtData, error: debtError } = await supabase
        .from('debts')
        .select('due_date')
        .eq('paid', false)
        .not('due_date', 'is', null);

        if (debtError || !debtData) return 0;

        const today = new Date();
        today.setHours(0, 0, 0, 0);

        const sevenDaysFromNow = new Date();
        sevenDaysFromNow.setHours(23, 59, 59, 999);
        sevenDaysFromNow.setDate(today.getDate() + 7);

        return debtData.filter(debt => {
          const dueDate = new Date(debt.due_date!);
          if (dueDate < today) return true;
          if (dueDate >= today && dueDate <= sevenDaysFromNow) return true;
          return false;
        }).length;
    },
    enabled: isAuthenticated, // Only fetch if authenticated
    refetchInterval: 60000, // Check every minute
  });

  const handleSelectContact = async (contactId: string) => {
    setActiveContactId(contactId);
    try {
        const { data, error } = await supabase.from('contacts').select('name').eq('id', contactId).single();
        if (error) throw error;
        setActiveContactName(data?.name || 'ملف شخصي');
        setActivePage('contacts');
    } catch(e) {
        console.error("Error fetching contact name", e);
        setActiveContactName('ملف شخصي');
        setActivePage('contacts');
    }
  };

  const handleBackToContacts = () => {
    setActiveContactId(null);
    setActiveContactName('');
    setActivePage('contacts');
  };

  // Helper to log activity (now can be called directly or via invalidation side effects in components)
  // Components will now use useQueryClient to invalidate queries instead of calling this.

  const renderPage = () => {
    if (activePage === 'contacts' && activeContactId) {
        return <ContactProfilePage 
            key={activeContactId} 
            contactId={activeContactId} 
            onBack={handleBackToContacts} 
        />;
    }

    switch (activePage) {
      case 'home': return <HomePage setActivePage={setActivePage} />;
      case 'accounts': return <AccountsPage />;
      case 'transactions': return <TransactionsPage />;
      case 'debts': return <DebtsPage onSelectContact={handleSelectContact} />;
      case 'contacts': return <ContactsPage onSelectContact={handleSelectContact} />;
      case 'categories': return <CategoriesPage />;
      case 'reports': return <ReportsPage />;
      case 'notes': return <NotesPage />;
      default: return <HomePage setActivePage={setActivePage}/>;
    }
  };

  if (!isAuthenticated) {
    return (
      <div className="min-h-screen font-sans flex items-center justify-center p-4 relative overflow-hidden" dir="rtl">
         {/* Ambient background elements */}
        <div className="absolute top-0 left-1/4 w-96 h-96 bg-cyan-500/20 rounded-full blur-[100px] animate-pulse-slow"></div>
        <div className="absolute bottom-0 right-1/4 w-96 h-96 bg-blue-600/20 rounded-full blur-[100px] animate-pulse-slow" style={{animationDelay: '2s'}}></div>

        <div className="glass-card w-full max-w-sm p-8 rounded-3xl shadow-2xl text-center animate-slide-up relative z-10">
          <div className="w-20 h-20 bg-gradient-to-br from-cyan-400 to-blue-600 rounded-2xl mx-auto mb-8 flex items-center justify-center shadow-lg shadow-cyan-500/30 rotate-3 hover:rotate-0 transition-transform duration-500">
             <WalletIcon className="w-10 h-10 text-white" />
          </div>
          <h1 className="text-3xl font-bold text-white mb-2 tracking-tight">أهلاً بعودتك</h1>
          <p className="text-slate-400 mb-8 text-sm font-medium">أدخل رمز المرور للمتابعة</p>
          <form onSubmit={handlePasswordSubmit} className="space-y-6">
            <div className="relative group">
                <input
                type="password"
                value={passwordInput}
                onChange={(e) => setPasswordInput(e.target.value)}
                className="w-full bg-slate-950/50 border border-slate-700/50 rounded-2xl p-4 text-white text-center text-2xl tracking-[0.5em] focus:outline-none focus:ring-2 focus:ring-cyan-500/50 focus:border-cyan-500 transition-all placeholder-slate-700 group-hover:border-slate-600"
                placeholder="••••"
                autoFocus
                />
            </div>
            {authError && <p className="text-rose-400 text-sm font-medium animate-bounce bg-rose-500/10 py-2 rounded-lg border border-rose-500/20">{authError}</p>}
            <button
              type="submit"
              className="w-full bg-gradient-to-r from-cyan-500 to-blue-600 hover:from-cyan-400 hover:to-blue-500 text-white font-bold py-4 rounded-2xl transition-all transform active:scale-95 shadow-lg shadow-cyan-500/20"
            >
              دخول
            </button>
          </form>
        </div>
      </div>
    );
  }

  return (
    <div className="min-h-screen font-sans pb-24 md:pb-0" dir="rtl">
        <Header 
            activePage={activePage} 
            onMenuClick={() => setSidebarOpen(true)}
            isProfilePage={!!activeContactId}
            profileName={activeContactName}
            onBack={handleBackToContacts}
        />
        <Sidebar isOpen={isSidebarOpen} onClose={() => setSidebarOpen(false)} activePage={activePage} setActivePage={setActivePage} />
        <main className="max-w-5xl mx-auto p-4 md:p-6 animate-fade-in">
            {renderPage()}
        </main>
        <BottomNav activePage={activePage} setActivePage={setActivePage} debtNotificationCount={debtNotificationCount} />
    </div>
  );
}

function App() {
    return (
        <QueryClientProvider client={queryClient}>
            <ToastProvider>
                <AppContent />
            </ToastProvider>
        </QueryClientProvider>
    )
}

export default App;

