                        <button onClick={handleDelete} className="py-3 px-6 bg-rose-600 hover:bg-rose-500 text-white rounded-xl transition font-bold shadow-lg">تأكيد الحذف</button>
                    </div>
                </Modal>
            )}
        </div>
    );
};

