            <ConfirmDialog 
                isOpen={modal.type === 'delete' && !!modal.account}
                title="حذف الحساب"
                message={`هل أنت متأكد من رغبتك في حذف حساب "${modal.account?.name}"؟ سيؤدي هذا الإجراء إلى حذف جميع البيانات المرتبطة بالحساب ولا يمكن التراجع عنه.`}
