                }

                const topCats = Array.from(categoryMap.values())
                    .sort((a, b) => b.amount - a.amount)
                    // Removed .slice(0, 4) to show more if possible, or keep it to limit list
                    .slice(0, 6); 

                setStats({ income: inc, expense: exp, topCategories: topCats });
