                        </div>
                    </div>
                </div>
                <YearlyChart data={Array.from({ length: 12 }, (_, i) => ({ income: yearlyData.income[i] || 0, expense: yearlyData.expense[i] || 0}))} />
            </div>

            {/* Recent Transactions List */}
            <div>
                <div className="flex justify-between items-end mb-4 px-1">
