const TransactionsPage: React.FC = () => {
    const queryClient = useQueryClient();
    const toast = useToast();
    const [searchTerm, setSearchTerm] = useState('');
    const [filters, setFilters] = useState<FilterValues>({
        types: ['income', 'expense', 'transfer'],
        date_from: '', date_to: '',
        accounts: [], categories: []
    });

    // Fetch Accounts & Categories for filtering
    const { data: accounts = [] } = useQuery({ queryKey: ['accounts'], queryFn: async () => (await supabase.from('accounts').select('*')).data as Account[] || [] });
    const { data: categories = [] } = useQuery({ queryKey: ['categories'], queryFn: async () => (await supabase.from('categories').select('*')).data as Category[] || [] });

    // --- Server-Side Infinite Scroll ---
    const PAGE_SIZE = 20;

    const {
        data,
        fetchNextPage,
        hasNextPage,
        isFetchingNextPage,
        isLoading,
        error
    } = useInfiniteQuery({
        queryKey: ['transactions', filters, searchTerm], // Refetch when filters/search change
        queryFn: async ({ pageParam = 0 }) => {
            const start = pageParam * PAGE_SIZE;
            const end = start + PAGE_SIZE - 1;

            let query = supabase
                .from('transactions')
                .select('*, accounts:account_id(name, currency), to_accounts:to_account_id(name), categories(name, color, icon)', { count: 'exact' })
                .order('date', { ascending: false })
                .range(start, end);

            // Apply Filters (Server-Side)
            if (filters.types.length > 0) {
                query = query.in('type', filters.types);
            }

            if (filters.date_from) {
                const from = new Date(filters.date_from);
                from.setHours(0,0,0,0);
                query = query.gte('date', from.toISOString());
            }

            if (filters.date_to) {
                const to = new Date(filters.date_to);
                to.setHours(23,59,59,999);
                query = query.lte('date', to.toISOString());
            }

            if (filters.accounts.length > 0) {
                query = query.in('account_id', filters.accounts);
            }

            if (searchTerm) {
                // Simple search on notes column
                query = query.ilike('notes', `%${searchTerm}%`);
            }

            const { data, error, count } = await query;
            if (error) throw error;

            return {
                transactions: data as Transaction[],
                totalCount: count || 0,
                nextPage: (data.length === PAGE_SIZE) ? pageParam + 1 : undefined
            };
        },
        initialPageParam: 0,
        getNextPageParam: (lastPage) => lastPage.nextPage,
    });

    const allTransactions = useMemo(() => {
        return data?.pages.flatMap(page => page.transactions) || [];
    }, [data]);

    // Aggregate summary from loaded data (Client-side estimation based on loaded data)
    // For accurate totals with pagination, we'd need a separate aggregation query, 
    // but for UI responsiveness we can just summarize loaded data or fetch stats separately.
    // Let's fetch strict stats separately for accuracy.
    const { data: stats } = useQuery({
        queryKey: ['transactions-stats', filters, searchTerm],
        queryFn: async () => {
             // Basic stat aggregation query
             let query = supabase.from('transactions').select('amount, type');
             // Apply same filters... (duplicated logic, ideally refactor into builder function)
             if (filters.types.length > 0) query = query.in('type', filters.types);
             if (filters.date_from) query = query.gte('date', new Date(filters.date_from).toISOString());
             if (filters.date_to) query = query.lte('date', new Date(filters.date_to).toISOString());
             if (filters.accounts.length > 0) query = query.in('account_id', filters.accounts);
             if (searchTerm) query = query.ilike('notes', `%${searchTerm}%`);

             const { data } = await query;
             const s = (data || []).reduce((acc: any, curr: any) => {
                 if (curr.type === 'income') acc.income += curr.amount;
                 if (curr.type === 'expense') acc.expense += curr.amount;
                 return acc;
             }, { income: 0, expense: 0 });
             return s;
        }
    });

    const summary = stats || { income: 0, expense: 0 };

    const groupedTransactions = useMemo(() => {
        return allTransactions.reduce((acc: Record<string, Transaction[]>, tx) => {
            const dateKey = formatDateGroup(tx.date);
            if (!acc[dateKey]) acc[dateKey] = [];
            acc[dateKey].push(tx);
            return acc;
        }, {});
    }, [allTransactions]);


    const [isFilterModalOpen, setIsFilterModalOpen] = useState(false);
    const [modal, setModal] = useState<{ type: 'edit' | 'delete' | null, transaction: Transaction | null }>({ type: null, transaction: null });
    const [isDetailModalOpen, setIsDetailModalOpen] = useState(false);
    const [selectedTransactionForDetail, setSelectedTransactionForDetail] = useState<Transaction | null>(null);

    const handleOpenDetailModal = (tx: Transaction) => {
        setSelectedTransactionForDetail(tx);
        setIsDetailModalOpen(true);
    };

    const handleCloseDetailModal = () => {
        setSelectedTransactionForDetail(null);
        setIsDetailModalOpen(false);
    };

    const handleOpenEditModalFromDetail = () => {
        if (!selectedTransactionForDetail) return;
        setModal({ type: 'edit', transaction: selectedTransactionForDetail });
        handleCloseDetailModal();
    };

    const handleOpenDeleteModalFromDetail = () => {
        if (!selectedTransactionForDetail) return;
        setModal({ type: 'delete', transaction: selectedTransactionForDetail });
        handleCloseDetailModal();
    };


    const handleSave = (description: string) => {
        setModal({ type: null, transaction: null });
        queryClient.invalidateQueries({ queryKey: ['transactions'] });
        queryClient.invalidateQueries({ queryKey: ['accounts'] }); // Balance updates
        queryClient.invalidateQueries({ queryKey: ['transactions-stats'] }); 
        toast.success(description);
    };

    const handleDelete = async () => {
        if (!modal.transaction) return;
        const { id, account_id, to_account_id, type, amount } = modal.transaction;

        try {
            if (type === 'transfer') {
                if (!account_id || !to_account_id) throw new Error("Transfer accounts not found");
                const { data: fromAcc } = await supabase.from('accounts').select('balance').eq('id', account_id).single();
                const { data: toAcc } = await supabase.from('accounts').select('balance').eq('id', to_account_id).single();
                if (!fromAcc || !toAcc) throw new Error("Could not fetch transfer accounts");
                await supabase.from('accounts').update({ balance: fromAcc.balance + amount }).eq('id', account_id);
                await supabase.from('accounts').update({ balance: toAcc.balance - amount }).eq('id', to_account_id);
            } else if(account_id) {
                const { data: acc } = await supabase.from('accounts').select('balance').eq('id', account_id).single();
                if (!acc) throw new Error("Account not found");
                const newBalance = type === 'income' ? acc.balance - amount : acc.balance + amount;
                await supabase.from('accounts').update({ balance: newBalance }).eq('id', account_id);
            }

            await supabase.from('transactions').delete().eq('id', id);

            // Log Activity
            logActivity(`حذف معاملة: ${formatCurrency(amount)} (${type === 'income' ? 'إيراد' : type === 'expense' ? 'مصروف' : 'تحويل'})`);

            handleSave('تم حذف المعاملة بنجاح');
        } catch (error: any) {
            console.error("Error deleting transaction:", error.message);
            toast.error('حدث خطأ أثناء الحذف.');
            setModal({ type: null, transaction: null });
        }
    };

    const activeFilterCount = useMemo(() => {
        let count = 0;
        if(filters.types.length !== 3) count++;
        if(filters.date_from || filters.date_to) count++;
        if(filters.accounts.length > 0) count++;
        return count;
    }, [filters]);

    return (
        <div className="space-y-6">
            <div className="grid grid-cols-3 gap-4 text-center">
                <div className="glass-card p-4 rounded-2xl border border-white/5">
                    <p className="text-xs text-emerald-400 font-bold mb-1">الدخل</p>
                    <p className="font-extrabold text-lg tracking-tight">{formatCurrency(summary.income)}</p>
                </div>
                <div className="glass-card p-4 rounded-2xl border border-white/5">
                    <p className="text-xs text-rose-400 font-bold mb-1">المصروف</p>
                    <p className="font-extrabold text-lg tracking-tight">{formatCurrency(summary.expense)}</p>
                </div>
                <div className="glass-card p-4 rounded-2xl border border-white/5">
                    <p className="text-xs text-cyan-400 font-bold mb-1">الصافي</p>
                    <p className="font-extrabold text-lg tracking-tight">{formatCurrency(summary.income - summary.expense)}</p>
                </div>
            </div>
            <div className="flex gap-3 items-center">
                <div className="relative flex-grow group">
                    <MagnifyingGlassIcon className="absolute right-4 top-1/2 -translate-y-1/2 w-5 h-5 text-slate-400 group-focus-within:text-cyan-400 transition-colors pointer-events-none" />
                    <input type="text" placeholder="ابحث في الملاحظات..." value={searchTerm} onChange={e => setSearchTerm(e.target.value)}
                        className="w-full bg-slate-900/50 p-3 pr-12 rounded-2xl text-white border border-slate-700 focus:border-cyan-500 focus:ring-1 focus:ring-cyan-500 focus:outline-none transition shadow-inner" />
                </div>
                <button onClick={() => setIsFilterModalOpen(true)} className={`relative flex-shrink-0 flex items-center justify-center h-12 w-12 rounded-2xl transition-all ${activeFilterCount > 0 ? 'bg-cyan-500/20 text-cyan-400 border border-cyan-500/50' : 'bg-slate-800 text-slate-400 border border-slate-700 hover:bg-slate-700'}`}>
                    <FunnelIcon className="w-5 h-5"/>
                    {activeFilterCount > 0 && <span className="absolute -top-1 -right-1 h-4 w-4 bg-cyan-500 text-white text-[10px] font-bold rounded-full flex items-center justify-center shadow-sm">{activeFilterCount}</span>}
                </button>
            </div>

            {isLoading ? <div className="space-y-3">{[...Array(5)].map((_,i) => <div key={i} className="h-20 bg-slate-800/50 rounded-2xl animate-pulse"></div>)}</div>
            : Object.keys(groupedTransactions).length === 0 ? <div className="text-center py-16 bg-slate-900/20 rounded-3xl border-dashed border-2 border-slate-800 text-slate-500">لا توجد معاملات تطابق بحثك.</div>
            : (
                <div className="space-y-6 pb-20">
                    {Object.entries(groupedTransactions).map(([date, txs]: [string, Transaction[]]) => (
                        <div key={date}>
                            <h3 className="font-bold text-sm text-slate-500 mb-3 px-2 sticky top-16 backdrop-blur-md bg-slate-950/30 rounded-lg inline-block z-10">{date}</h3>
                            <div className="space-y-2">
                                {txs.map(tx => {
                                    const categoryIconName = tx.categories?.icon;
                                    const CategoryIcon = (categoryIconName && iconMap.hasOwnProperty(categoryIconName)) ? iconMap[categoryIconName] : null;
                                    return (
                                        <button key={tx.id} onClick={() => handleOpenDetailModal(tx)}
                                            className="w-full text-right glass-card p-4 rounded-2xl flex justify-between items-center hover:bg-white/5 transition-all group border-transparent hover:border-white/10 active:scale-[0.98] duration-200 hover:shadow-lg hover:shadow-black/20">
                                            <div className="flex items-center gap-4">
                                                <div className={`w-12 h-12 rounded-2xl flex items-center justify-center shadow-md transition-transform group-hover:scale-110 ${
                                                    tx.type === 'income' ? 'bg-emerald-500/10 text-emerald-400 border border-emerald-500/20' : 
                                                    tx.type === 'expense' ? 'bg-rose-500/10 text-rose-400 border border-rose-500/20' : 'bg-indigo-500/10 text-indigo-400 border border-indigo-500/20'
                                                }`}>
                                                    {CategoryIcon ? <CategoryIcon className="w-6 h-6"/> : <TransactionIcon type={tx.type} />}
                                                </div>
                                                <div>
                                                    <p className="font-bold text-white text-base mb-0.5 line-clamp-1">{tx.notes || tx.categories?.name || (tx.type === 'transfer' ? `تحويل إلى ${tx.to_accounts?.name}` : 'معاملة')}</p>
                                                    <p className="text-xs text-slate-400 font-medium">{tx.accounts?.name || 'حساب محذوف'}</p>
                                                </div>
                                            </div>
                                            <p className={`font-extrabold text-lg whitespace-nowrap ${tx.type === 'income' ? 'text-emerald-400' : tx.type === 'expense' ? 'text-rose-400' : 'text-indigo-400'}`}>
                                                {formatCurrency(tx.amount)}
                                            </p>
                                        </button>
                                    );
                                })}
                            </div>
                        </div>
                    ))}

                    {hasNextPage && (
                        <div className="text-center pt-4">
                            <button 
                                onClick={() => fetchNextPage()} 
                                disabled={isFetchingNextPage}
                                className="px-6 py-3 bg-slate-800 hover:bg-slate-700 text-slate-300 font-bold rounded-xl transition disabled:opacity-50 border border-slate-700 hover:text-white"
                            >
                                {isFetchingNextPage ? 'جاري التحميل...' : 'عرض المزيد من المعاملات'}
                            </button>
                        </div>
                    )}
                </div>
            )}

            {isFilterModalOpen && (
                <FilterModal 
                    accounts={accounts} 
                    categories={categories} 
                    initialFilters={filters}
                    onApply={(newFilters) => { setFilters(newFilters); setIsFilterModalOpen(false); }}
                    onClose={() => setIsFilterModalOpen(false)}
                />
            )}

            {isDetailModalOpen && selectedTransactionForDetail && (
                <Modal title="تفاصيل المعاملة" onClose={handleCloseDetailModal}>
                    <TransactionDetailContent
                        transaction={selectedTransactionForDetail}
                        onEdit={handleOpenEditModalFromDetail}
                        onDelete={handleOpenDeleteModalFromDetail}
                    />
                </Modal>
            )}

            {modal.type === 'edit' && modal.transaction && (
                <Modal title="تعديل المعاملة" onClose={() => setModal({ type: null, transaction: null })}>
                    {modal.transaction.type === 'transfer' ? (
                        <p className="text-slate-400 text-center py-4">لا يمكن تعديل التحويلات من هنا. يرجى حذفها وإعادة إنشائها.</p>
                    ) : (
                        <TransactionForm
                            transaction={modal.transaction}
                            onSave={() => handleSave('تم تعديل المعاملة بنجاح')}
                            onCancel={() => setModal({ type: null, transaction: null })}
                            accounts={accounts}
                            categories={categories}
                        />
                    )}
                </Modal>
            )}

            <ConfirmDialog 
                isOpen={modal.type === 'delete' && !!modal.transaction}
                title="تأكيد حذف المعاملة"
                message="هل أنت متأكد تماماً؟ سيتم عكس تأثير هذه المعاملة على رصيد الحساب. لا يمكن التراجع عن هذا الإجراء."
                confirmText="حذف المعاملة"
                onConfirm={handleDelete}
                onCancel={() => setModal({ type: null, transaction: null })}
            />

        </div>
    );
};

export default TransactionsPage;

import React, { useState, useEffect, useCallback, useMemo } from 'react';
import { supabase } from '../lib/supabase';
import { Account, Transaction } from '../types';
import { useToast } from './Toast';
import ConfirmDialog from './ConfirmDialog';
import { 
    EllipsisVerticalIcon, PlusIcon, XMarkIcon, WalletIcon, 
    ArrowUpIcon, ArrowDownIcon, ArrowsRightLeftIcon,
    CalendarDaysIcon, PencilSquareIcon, TrashIcon, CheckCircleIcon, InformationCircleIcon,
    PaintBrushIcon, LandmarkIcon, BanknoteIcon, BriefcaseIcon
} from './icons';
import { logActivity } from '../lib/logger';

const formatCurrency = (amount: number, currency: string = 'د.ل') => {
    return new Intl.NumberFormat('ar-LY', { style: 'currency', currency: 'LYD', minimumFractionDigits: 0 }).format(amount).replace('LYD', currency);
};

// --- Modern Card Themes ---
const THEME_OPTIONS = [
    { id: 'blue', name: 'أزرق ليلي', class: 'bg-gradient-to-bl from-slate-900 via-blue-900 to-slate-900 border-blue-500/30', preview: 'bg-blue-900' },
    { id: 'emerald', name: 'زمردي', class: 'bg-gradient-to-bl from-emerald-900 via-teal-900 to-slate-900 border-emerald-500/30', preview: 'bg-emerald-900' },
    { id: 'purple', name: 'بنفسجي', class: 'bg-gradient-to-bl from-fuchsia-900 via-purple-900 to-slate-900 border-fuchsia-500/30', preview: 'bg-fuchsia-900' },
    { id: 'rose', name: 'وردي غامق', class: 'bg-gradient-to-bl from-rose-900 via-pink-900 to-slate-900 border-rose-500/30', preview: 'bg-rose-900' },
    { id: 'amber', name: 'كهرماني', class: 'bg-gradient-to-bl from-amber-900 via-orange-900 to-slate-900 border-amber-500/30', preview: 'bg-amber-900' },
    { id: 'cyan', name: 'سماوي', class: 'bg-gradient-to-bl from-cyan-900 via-sky-900 to-slate-900 border-cyan-500/30', preview: 'bg-cyan-900' },
    { id: 'slate', name: 'داكن', class: 'bg-gradient-to-bl from-slate-800 via-slate-900 to-black border-slate-600/30', preview: 'bg-slate-800' },
    { id: 'gold', name: 'ذهبي', class: 'bg-gradient-to-bl from-yellow-900 via-amber-800 to-slate-900 border-yellow-500/30', preview: 'bg-yellow-900' },
];

const getDefaultThemeForType = (type: string) => {
    switch (type) {
        case 'بنكي': return 'blue';
        case 'نقدي': return 'emerald';
        case 'مخصص': return 'purple';
        default: return 'slate';
    }
};

const getAccountTypeIcon = (type: string) => {
    switch (type) {
        case 'بنكي': return LandmarkIcon;
        case 'نقدي': return BanknoteIcon;
        case 'مخصص': return BriefcaseIcon;
        default: return WalletIcon;
    }
};

// ... AccountDetailsModal ... (keep existing code, just copy it to ensure file integrity)
const AccountDetailsModal: React.FC<{
    account: Account;
    onClose: () => void;
    onEdit: () => void;
    onDelete: () => void;
}> = ({ account, onClose, onEdit, onDelete }) => {
    const [transactions, setTransactions] = useState<Transaction[]>([]);
    const [loading, setLoading] = useState(true);
    const [stats, setStats] = useState({ income: 0, expense: 0, transferIn: 0, transferOut: 0 });

    // Pagination State
    const [page, setPage] = useState(0);
    const [hasMore, setHasMore] = useState(true);
    const [loadingMore, setLoadingMore] = useState(false);
    const PAGE_SIZE = 10;

    // Fetch Stats (Totals) separately to allow accurate stats even with pagination
    useEffect(() => {
        const fetchStats = async () => {
            const { data, error } = await supabase
                .from('transactions')
                .select('amount, type, account_id, to_account_id')
                .or(`account_id.eq.${account.id},to_account_id.eq.${account.id}`);

            if (!error && data) {
                let inc = 0, exp = 0, tIn = 0, tOut = 0;
                data.forEach((tx: any) => {
                    if (tx.type === 'income' && tx.account_id === account.id) inc += tx.amount;
                    if (tx.type === 'expense' && tx.account_id === account.id) exp += tx.amount;
                    if (tx.type === 'transfer') {
                        if (tx.account_id === account.id) tOut += tx.amount;
                        if (tx.to_account_id === account.id) tIn += tx.amount;
                    }
                });
                setStats({ income: inc, expense: exp, transferIn: tIn, transferOut: tOut });
            }
        };
        fetchStats();
    }, [account.id]);

    // Fetch Transactions with Pagination
    const fetchTransactions = useCallback(async (pageNumber: number, isLoadMore = false) => {
        if (!isLoadMore) setLoading(true);
        else setLoadingMore(true);

        const from = pageNumber * PAGE_SIZE;
        const to = from + PAGE_SIZE - 1;

        const { data, error } = await supabase
            .from('transactions')
            // Fix: Explicitly specify 'accounts:account_id' to avoid ambiguity with 'to_account_id'
            .select('*, categories(name, icon, color), accounts:account_id(name), to_accounts:to_account_id(name)')
            .or(`account_id.eq.${account.id},to_account_id.eq.${account.id}`)
            .order('date', { ascending: false })
            .range(from, to);

        if (!error && data) {
            const newTransactions = data as unknown as Transaction[];

            if (newTransactions.length < PAGE_SIZE) {
                setHasMore(false);
            } else {
                setHasMore(true);
            }

            setTransactions(prev => isLoadMore ? [...prev, ...newTransactions] : newTransactions);
        } else if (error) {
            console.error("Error fetching transactions:", error.message);
        }

        setLoading(false);
        setLoadingMore(false);
    }, [account.id]);

    useEffect(() => {
        // Initial load
        setPage(0);
        setTransactions([]);
        setHasMore(true);
        fetchTransactions(0, false);
    }, [fetchTransactions]);

    const handleLoadMore = () => {
        const nextPage = page + 1;
        setPage(nextPage);
        fetchTransactions(nextPage, true);
    };

    const netFlow = (stats.income + stats.transferIn) - (stats.expense + stats.transferOut);

    // Resolve Theme
    const themeId = account.theme || getDefaultThemeForType(account.type);
    const themeOption = THEME_OPTIONS.find(t => t.id === themeId) || THEME_OPTIONS[0];

    // Menu logic inside modal
    const [isMenuOpen, setIsMenuOpen] = useState(false);

    return (
        <div className="fixed inset-0 z-50 bg-black/80 backdrop-blur-md flex items-center justify-center p-4 animate-fade-in">
            <div className={`w-full max-w-2xl h-[90vh] rounded-3xl border border-white/10 shadow-2xl flex flex-col overflow-hidden animate-slide-up ${themeOption.class.replace('bg-gradient-to-bl', 'bg-gradient-to-br')}`}>

                {/* Header */}
                <div className="p-6 border-b border-white/5 flex justify-between items-start bg-black/20">
                    <div>
                        <p className="text-white/60 text-sm font-medium mb-1">تفاصيل الحساب</p>
                        <h2 className="text-2xl font-bold text-white flex items-center gap-2">
                            {account.name}
                            <span className="text-xs px-2 py-1 rounded-full bg-white/10 border border-white/10 text-white font-normal">{account.type}</span>
                        </h2>
                    </div>
                    <div className="flex items-center gap-2">
                         <div className="relative">
                             <button onClick={() => setIsMenuOpen(!isMenuOpen)} className="p-2 rounded-full hover:bg-white/10 text-white/70 hover:text-white transition">
                                 <EllipsisVerticalIcon className="w-6 h-6" />
                             </button>
                             {isMenuOpen && (
                                <>
                                <div className="fixed inset-0 z-10" onClick={() => setIsMenuOpen(false)}></div>
                                <div className="absolute left-0 mt-2 w-48 bg-slate-900 border border-white/10 rounded-xl shadow-xl z-20 overflow-hidden animate-fade-in">
                                    <button onClick={() => { onEdit(); setIsMenuOpen(false); }} className="flex items-center gap-3 w-full text-right px-4 py-3 text-sm text-slate-200 hover:bg-white/10 transition">
                                        <PencilSquareIcon className="w-4 h-4 text-cyan-400"/> تعديل الحساب
                                    </button>
                                    <button onClick={() => { onDelete(); setIsMenuOpen(false); }} className="flex items-center gap-3 w-full text-right px-4 py-3 text-sm text-rose-400 hover:bg-white/10 transition">
                                        <TrashIcon className="w-4 h-4"/> حذف الحساب
                                    </button>
                                </div>
                                </>
                             )}
                         </div>
                        <button onClick={onClose} className="p-2 rounded-full bg-black/20 hover:bg-black/40 text-white transition">
                            <XMarkIcon className="w-6 h-6" />
                        </button>
                    </div>
                </div>

                {/* Content */}
                <div className="flex-1 overflow-y-auto custom-scrollbar p-6 space-y-6 bg-slate-900/40 backdrop-blur-sm">

                    {/* Hero Stats */}
                    <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                        <div className={`glass-card p-5 rounded-2xl border border-white/10 relative overflow-hidden`}>
                             <div className="absolute -right-6 -top-6 w-24 h-24 bg-white/10 rounded-full blur-2xl"></div>
                            <p className="text-white/60 text-sm mb-1">الرصيد الحالي</p>
                            <p className="text-3xl font-extrabold text-white tracking-tight">{formatCurrency(account.balance, account.currency)}</p>
                        </div>
                        <div className="glass-card p-5 rounded-2xl border border-white/5 flex flex-col justify-center">
                             <p className="text-slate-400 text-sm mb-1">صافي الحركة (المسجلة)</p>
                             <p className={`text-xl font-bold ${netFlow >= 0 ? 'text-emerald-400' : 'text-rose-400'}`}>
                                 {netFlow > 0 ? '+' : ''}{formatCurrency(netFlow, account.currency)}
                             </p>
                        </div>
                    </div>

                    {/* Quick Stats Grid */}
                    <div className="grid grid-cols-3 gap-3">
                        <div className="bg-slate-800/50 p-3 rounded-xl border border-white/5 text-center">
                            <ArrowDownIcon className="w-5 h-5 text-emerald-400 mx-auto mb-2" />
                            <p className="text-xs text-slate-400 mb-1">دخل + وارد</p>
                            <p className="font-bold text-emerald-400 text-sm">{formatCurrency(stats.income + stats.transferIn)}</p>
                        </div>
                        <div className="bg-slate-800/50 p-3 rounded-xl border border-white/5 text-center">
                            <ArrowUpIcon className="w-5 h-5 text-rose-400 mx-auto mb-2" />
                            <p className="text-xs text-slate-400 mb-1">صرف + صادر</p>
                            <p className="font-bold text-rose-400 text-sm">{formatCurrency(stats.expense + stats.transferOut)}</p>
                        </div>
                         <div className="bg-slate-800/50 p-3 rounded-xl border border-white/5 text-center">
                            <ArrowsRightLeftIcon className="w-5 h-5 text-indigo-400 mx-auto mb-2" />
                            <p className="text-xs text-slate-400 mb-1">العمليات</p>
                            <p className="font-bold text-indigo-400 text-sm">{transactions.length}</p>
                        </div>
                    </div>

                    {/* Transactions List */}
                    <div>
                        <h3 className="text-white font-bold mb-4 flex items-center gap-2">
                            <CalendarDaysIcon className="w-5 h-5 text-cyan-400" />
                            سجل المعاملات
                        </h3>
                        {loading && transactions.length === 0 ? (
                             <div className="space-y-3">{[1,2,3].map(i => <div key={i} className="h-16 bg-slate-800 rounded-xl animate-pulse"></div>)}</div>
                        ) : transactions.length === 0 ? (
                            <div className="text-center py-10 text-slate-500 bg-slate-800/30 rounded-2xl border border-dashed border-slate-700">
                                لا توجد معاملات مسجلة لهذا الحساب.
                            </div>
                        ) : (
                            <div className="space-y-3">
                                {transactions.map(tx => {
                                    const isTransfer = tx.type === 'transfer';
                                    const isIncome = tx.type === 'income' || (isTransfer && tx.to_account_id === account.id);

                                    return (
                                        <div key={tx.id} className="flex items-center justify-between p-4 bg-slate-800/40 border border-white/5 rounded-2xl hover:bg-slate-800/80 transition group">
                                            <div className="flex items-center gap-4">
                                                <div className={`w-10 h-10 rounded-xl flex items-center justify-center ${isIncome ? 'bg-emerald-500/10 text-emerald-400' : 'bg-rose-500/10 text-rose-400'}`}>
                                                    {isTransfer ? <ArrowsRightLeftIcon className="w-5 h-5"/> : isIncome ? <ArrowDownIcon className="w-5 h-5"/> : <ArrowUpIcon className="w-5 h-5"/>}
                                                </div>
                                                <div>
                                                    <p className="text-white font-bold text-sm">
                                                        {tx.notes || (isTransfer ? (isIncome ? `تحويل من ${tx.accounts?.name}` : `تحويل إلى ${tx.to_accounts?.name}`) : tx.categories?.name || 'بدون عنوان')}
                                                    </p>
                                                    <p className="text-xs text-slate-500">
                                                        {new Date(tx.date).toLocaleDateString('ar-LY', {day:'numeric', month:'long', year:'numeric'})}
                                                    </p>
                                                </div>
                                            </div>
                                            <span className={`font-bold ${isIncome ? 'text-emerald-400' : 'text-rose-400'}`}>
                                                {isIncome ? '+' : '-'}{formatCurrency(tx.amount)}
                                            </span>
                                        </div>
                                    );
                                })}

                                {hasMore && (
                                    <button 
                                        onClick={handleLoadMore} 
                                        disabled={loadingMore}
                                        className="w-full py-3 mt-4 text-sm font-bold text-cyan-400 bg-slate-800/50 hover:bg-slate-800 border border-dashed border-slate-700 rounded-xl transition-all flex items-center justify-center gap-2"
                                    >
                                        {loadingMore ? (
                                            <>
                                                <div className="w-4 h-4 border-2 border-cyan-400 border-t-transparent rounded-full animate-spin"></div>
                                                جاري التحميل...
                                            </>
                                        ) : (
                                            <>عرض المزيد من المعاملات</>
                                        )}
                                    </button>
                                )}
                            </div>
                        )}
                    </div>
                </div>
            </div>
        </div>
    );
};

// ... AccountForm ... (keep existing)
const AccountForm: React.FC<{ account?: Account | null; onSave: () => void; onCancel: () => void; }> = ({ account, onSave, onCancel }) => {
    const toast = useToast();
    const [name, setName] = useState(account?.name || '');
    const [type, setType] = useState(account?.type || 'بنكي');
    const [balance, setBalance] = useState(account?.balance?.toString() || '0');
    const [currency, setCurrency] = useState(account?.currency || 'د.ل');
    const [theme, setTheme] = useState(account?.theme || 'blue');
    const [isSaving, setIsSaving] = useState(false);

    useEffect(() => {
        if (!account && type) {
            setTheme(getDefaultThemeForType(type));
        }
    }, [type, account]);

    const handleSubmit = async (e: React.FormEvent) => {
        e.preventDefault();
        setIsSaving(true);
        const accountData = { name, type, balance: parseFloat(balance), currency, theme };
        const { error } = account?.id ? await supabase.from('accounts').update(accountData).eq('id', account.id) : await supabase.from('accounts').insert(accountData);
        if (!error) {
            const action = account?.id ? 'تعديل' : 'إضافة';
            logActivity(`${action} حساب: ${name} (الرصيد: ${formatCurrency(parseFloat(balance))})`);
            onSave();
        } else {
            console.error(error);
            toast.error('حدث خطأ أثناء حفظ الحساب');
        }
        setIsSaving(false);
    };

    return (
        <form onSubmit={handleSubmit} className="space-y-5">
            <div className="space-y-1">
                <label className="text-sm text-slate-400 font-medium">اسم الحساب</label>
                <input type="text" value={name} onChange={e => setName(e.target.value)} placeholder="مثلاً: مصرف الجمهورية" required className="w-full bg-slate-800 border border-slate-700 rounded-xl p-3 text-white focus:border-cyan-500 focus:ring-1 focus:ring-cyan-500 outline-none transition" />
            </div>

            <div className="grid grid-cols-2 gap-4">
                <div className="space-y-1">
                    <label className="text-sm text-slate-400 font-medium">نوع الحساب</label>
                    <select value={type} onChange={e => setType(e.target.value)} className="w-full bg-slate-800 border border-slate-700 rounded-xl p-3 text-white outline-none focus:border-cyan-500">
                        <option value="بنكي">بنكي</option>
                        <option value="نقدي">نقدي</option>
                        <option value="مخصص">مخصص</option>
                    </select>
                </div>
                 <div className="space-y-1">
                    <label className="text-sm text-slate-400 font-medium">الرصيد الحالي</label>
                    <input type="number" step="0.01" value={balance} onChange={e => setBalance(e.target.value)} placeholder="0.00" required className="w-full bg-slate-800 border border-slate-700 rounded-xl p-3 text-white outline-none focus:border-cyan-500" />
                </div>
            </div>

            <div className="space-y-2">
                <label className="text-sm text-slate-400 font-medium flex items-center gap-2">
                    <PaintBrushIcon className="w-4 h-4"/>
                    تخصيص المظهر
                </label>
                <div className="grid grid-cols-4 gap-3">
                    {THEME_OPTIONS.map(opt => (
                        <button
                            key={opt.id}
                            type="button"
