        };

        chartRef.current = new (window as any).Chart(ctx, chartConfig);
        return () => { chartRef.current?.destroy(); };
    }, [data]);

    return <div className="h-56 lg:h-72 w-full"><canvas ref={canvasRef}></canvas></div>;
